INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ecev2$Installation and Configuration$ecev2$, 3, $ecev2$SINGLE$ecev2$::"QType", $ecev2$In `elasticsearch.yml`, which setting explicitly assigns a node ONLY the master-eligible role and removes the data role?$ecev2$, $ecev2$[{"id":"a","text":"node.master: true"},{"id":"b","text":"node.roles: [ master ]"},{"id":"c","text":"node.type: master-only"},{"id":"d","text":"cluster.master.only: true"}]$ecev2$::jsonb, $ecev2$["b"]$ecev2$::jsonb, $ecev2$Since Elasticsearch 7.9 node roles are declared with the `node.roles` list. `node.roles: [ master ]` makes the node master-eligible and not a data node. The legacy `node.master: true` boolean form is deprecated and does not by itself drop the data role.$ecev2$, $ecev2$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/modules-node.html","label":"Elasticsearch Reference — Node roles"}]$ecev2$::jsonb, $ecev2$PUBLISHED$ecev2$::"QStatus", $ecev2$manual:elastic-seed$ecev2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $ecev2$ECE-P1$ecev2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ecev2$In `elasticsearch.yml`, which setting explicitly assigns a node ONLY the master-eligible role and removes the data role?$ecev2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ecev2$Installation and Configuration$ecev2$, 3, $ecev2$SINGLE$ecev2$::"QType", $ecev2$When forming a brand-new multi-node cluster for the first time, which setting names the initial set of master-eligible nodes used to bootstrap the cluster?$ecev2$, $ecev2$[{"id":"a","text":"discovery.seed_hosts"},{"id":"b","text":"cluster.initial_master_nodes"},{"id":"c","text":"discovery.zen.minimum_master_nodes"},{"id":"d","text":"gateway.recover_after_nodes"}]$ecev2$::jsonb, $ecev2$["b"]$ecev2$::jsonb, $ecev2$`cluster.initial_master_nodes` performs the one-time cluster bootstrap and must be set only on the very first cluster formation. `discovery.seed_hosts` lists addresses for node discovery. `minimum_master_nodes` was removed in 7.0. `gateway.recover_after_nodes` controls recovery, not bootstrap.$ecev2$, $ecev2$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/modules-discovery-bootstrap-cluster.html","label":"Elasticsearch Reference — Bootstrap a cluster"}]$ecev2$::jsonb, $ecev2$PUBLISHED$ecev2$::"QStatus", $ecev2$manual:elastic-seed$ecev2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $ecev2$ECE-P1$ecev2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ecev2$When forming a brand-new multi-node cluster for the first time, which setting names the initial set of master-eligible nodes used to bootstrap the cluster?$ecev2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ecev2$Installation and Configuration$ecev2$, 3, $ecev2$MULTI$ecev2$::"QType", $ecev2$Select ALL true statements about node discovery and cluster formation in Elasticsearch 8.x.$ecev2$, $ecev2$[{"id":"a","text":"`discovery.seed_hosts` provides the list of addresses a node probes to find other nodes."},{"id":"b","text":"`cluster.initial_master_nodes` should be removed (or left unset) after the cluster has formed for the first time."},{"id":"c","text":"Every node must list every other node in `discovery.seed_hosts` for the cluster to function."},{"id":"d","text":"Only master-eligible nodes participate in master elections."}]$ecev2$::jsonb, $ecev2$["a","b","d"]$ecev2$::jsonb, $ecev2$`discovery.seed_hosts` only needs to reference enough master-eligible nodes for discovery to converge — not every node. `cluster.initial_master_nodes` is a one-time bootstrap setting. Only master-eligible nodes vote in elections.$ecev2$, $ecev2$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/modules-discovery.html","label":"Elasticsearch Reference — Discovery and cluster formation"},{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/modules-node.html","label":"Elasticsearch Reference — Node roles"}]$ecev2$::jsonb, $ecev2$PUBLISHED$ecev2$::"QStatus", $ecev2$manual:elastic-seed$ecev2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $ecev2$ECE-P1$ecev2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ecev2$Select ALL true statements about node discovery and cluster formation in Elasticsearch 8.x.$ecev2$);
