INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ecev2$Indexing Data$ecev2$, 3, $ecev2$SINGLE$ecev2$::"QType", $ecev2$Using the Index API, `PUT my-index/_doc/1` versus `POST my-index/_doc` differ in that:$ecev2$, $ecev2$[{"id":"a","text":"PUT requires an explicit document ID; POST auto-generates an ID if none is given."},{"id":"b","text":"POST requires an explicit document ID; PUT auto-generates one."},{"id":"c","text":"PUT only updates, POST only creates."},{"id":"d","text":"There is no difference; both require an ID."}]$ecev2$::jsonb, $ecev2$["a"]$ecev2$::jsonb, $ecev2$`PUT /index/_doc/<id>` indexes with a caller-supplied ID (create or overwrite). `POST /index/_doc` without an ID lets Elasticsearch auto-generate one. Use `_create` to fail if the ID already exists.$ecev2$, $ecev2$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/docs-index_.html","label":"Elasticsearch Reference — Index API"}]$ecev2$::jsonb, $ecev2$PUBLISHED$ecev2$::"QStatus", $ecev2$manual:elastic-seed$ecev2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $ecev2$ECE-P1$ecev2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ecev2$Using the Index API, `PUT my-index/_doc/1` versus `POST my-index/_doc` differ in that:$ecev2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ecev2$Indexing Data$ecev2$, 3, $ecev2$SINGLE$ecev2$::"QType", $ecev2$In a `_bulk` request, what is required between each action/metadata line and its optional source document?$ecev2$, $ecev2$[{"id":"a","text":"A JSON array wrapping all operations"},{"id":"b","text":"Each line must be a complete JSON object/newline-delimited, and the body must end with a newline"},{"id":"c","text":"A comma separating every operation"},{"id":"d","text":"All operations must target the same document ID"}]$ecev2$::jsonb, $ecev2$["b"]$ecev2$::jsonb, $ecev2$The Bulk API uses newline-delimited JSON (NDJSON): an action line followed (for index/create/update) by a source line, each on its own line, with a trailing newline. It is NOT a JSON array and operations are independent.$ecev2$, $ecev2$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/docs-bulk.html","label":"Elasticsearch Reference — Bulk API"}]$ecev2$::jsonb, $ecev2$PUBLISHED$ecev2$::"QStatus", $ecev2$manual:elastic-seed$ecev2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $ecev2$ECE-P1$ecev2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ecev2$In a `_bulk` request, what is required between each action/metadata line and its optional source document?$ecev2$);
