INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ecev2$Queries$ecev2$, 2, $ecev2$SINGLE$ecev2$::"QType", $ecev2$Which query analyzes the input text and is the standard choice for full-text search on an analyzed `text` field?$ecev2$, $ecev2$[{"id":"a","text":"term"},{"id":"b","text":"match"},{"id":"c","text":"exists"},{"id":"d","text":"ids"}]$ecev2$::jsonb, $ecev2$["b"]$ecev2$::jsonb, $ecev2$The `match` query runs the search text through the field analyzer, making it the canonical full-text query. `term` does NOT analyze input and is for exact tokens (keyword/numeric). `exists` and `ids` are structural.$ecev2$, $ecev2$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/full-text-queries.html","label":"Elasticsearch Reference — Full text queries"}]$ecev2$::jsonb, $ecev2$PUBLISHED$ecev2$::"QStatus", $ecev2$manual:elastic-seed$ecev2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $ecev2$ECE-P1$ecev2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ecev2$Which query analyzes the input text and is the standard choice for full-text search on an analyzed `text` field?$ecev2$);
