INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ecev2$Mappings and Text Analysis$ecev2$, 2, $ecev2$SINGLE$ecev2$::"QType", $ecev2$Which statement about `text` versus `keyword` field types is correct?$ecev2$, $ecev2$[{"id":"a","text":"text is analyzed/tokenized for full-text search; keyword is stored as a single exact token for filtering, sorting and aggregations."},{"id":"b","text":"keyword is analyzed for full-text search; text is not analyzed."},{"id":"c","text":"Both are analyzed identically."},{"id":"d","text":"text supports aggregations by default; keyword does not."}]$ecev2$::jsonb, $ecev2$["a"]$ecev2$::jsonb, $ecev2$A `text` field is passed through an analyzer and tokenized for relevance search but is not efficient for aggregations/sorting (fielddata disabled by default). A `keyword` field is indexed verbatim and is used for exact match, sort, and aggregations.$ecev2$, $ecev2$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/mapping-types.html","label":"Elasticsearch Reference — Field data types"}]$ecev2$::jsonb, $ecev2$PUBLISHED$ecev2$::"QStatus", $ecev2$manual:elastic-seed$ecev2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $ecev2$ECE-P1$ecev2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ecev2$Which statement about `text` versus `keyword` field types is correct?$ecev2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ecev2$Mappings and Text Analysis$ecev2$, 3, $ecev2$SINGLE$ecev2$::"QType", $ecev2$You want a single source field indexed both as analyzed `text` (for search) and as `keyword` (for aggregations). The idiomatic mapping uses:$ecev2$, $ecev2$[{"id":"a","text":"Two separate top-level fields you must populate yourself"},{"id":"b","text":"A multi-field: a `text` field with a `fields.keyword` sub-field of type keyword"},{"id":"c","text":"A `runtime` field of type keyword"},{"id":"d","text":"The `copy_to` parameter pointing to itself"}]$ecev2$::jsonb, $ecev2$["b"]$ecev2$::jsonb, $ecev2$Multi-fields index the same value multiple ways. The common pattern is a `text` field with `fields: { keyword: { type: "keyword", ignore_above: 256 } }`. Runtime fields are computed at query time, not indexed for aggregations efficiently.$ecev2$, $ecev2$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/multi-fields.html","label":"Elasticsearch Reference — multi-fields"}]$ecev2$::jsonb, $ecev2$PUBLISHED$ecev2$::"QStatus", $ecev2$manual:elastic-seed$ecev2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $ecev2$ECE-P1$ecev2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ecev2$You want a single source field indexed both as analyzed `text` (for search) and as `keyword` (for aggregations). The idiomatic mapping uses:$ecev2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ecev2$Mappings and Text Analysis$ecev2$, 3, $ecev2$SINGLE$ecev2$::"QType", $ecev2$With dynamic mapping enabled (the default), what happens when you index a document containing a previously unseen field `price` with a JSON number?$ecev2$, $ecev2$[{"id":"a","text":"The document is rejected until you add an explicit mapping."},{"id":"b","text":"Elasticsearch dynamically adds a mapping for `price` (e.g. as long or float) and indexes the document."},{"id":"c","text":"The field is stored but never indexed or searchable."},{"id":"d","text":"The whole index becomes read-only."}]$ecev2$::jsonb, $ecev2$["b"]$ecev2$::jsonb, $ecev2$Default dynamic mapping detects the JSON type and creates a field mapping automatically. Setting `dynamic: strict` would reject unknown fields; `dynamic: false` would store but not index them.$ecev2$, $ecev2$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/mapping.html","label":"Elasticsearch Reference — Mapping"}]$ecev2$::jsonb, $ecev2$PUBLISHED$ecev2$::"QStatus", $ecev2$manual:elastic-seed$ecev2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $ecev2$ECE-P1$ecev2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ecev2$With dynamic mapping enabled (the default), what happens when you index a document containing a previously unseen field `price` with a JSON number?$ecev2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ecev2$Mappings and Text Analysis$ecev2$, 3, $ecev2$SINGLE$ecev2$::"QType", $ecev2$A `runtime` field defined in the mapping is best described as:$ecev2$, $ecev2$[{"id":"a","text":"A field evaluated at query time via a script (or from source), not indexed at ingest, trading query speed for schema flexibility."},{"id":"b","text":"A field that is indexed faster than normal fields."},{"id":"c","text":"A field that can only be a date."},{"id":"d","text":"An alias to another index."}]$ecev2$::jsonb, $ecev2$["a"]$ecev2$::jsonb, $ecev2$Runtime fields are computed when the query runs (or at index time if backed by a script-on-index), enabling schema-on-read without reindexing — at the cost of per-query computation versus pre-indexed fields.$ecev2$, $ecev2$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/runtime.html","label":"Elasticsearch Reference — Runtime fields"}]$ecev2$::jsonb, $ecev2$PUBLISHED$ecev2$::"QStatus", $ecev2$manual:elastic-seed$ecev2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $ecev2$ECE-P1$ecev2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ecev2$A `runtime` field defined in the mapping is best described as:$ecev2$);
