INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ecev2$Installation and Configuration$ecev2$, 2, $ecev2$SINGLE$ecev2$::"QType", $ecev2$Where is the JVM heap size for an Elasticsearch node configured?$ecev2$, $ecev2$[{"id":"a","text":"In `elasticsearch.yml` under `index.heap`"},{"id":"b","text":"In `jvm.options` (or a file in `jvm.options.d/`) via `-Xms`/`-Xmx`"},{"id":"c","text":"In `log4j2.properties`"},{"id":"d","text":"Via the `_cluster/settings` API"}]$ecev2$::jsonb, $ecev2$["b"]$ecev2$::jsonb, $ecev2$Heap is a JVM concern set in `jvm.options` (or drop-in files in `jvm.options.d/`) using `-Xms`/`-Xmx`. It is not an Elasticsearch YAML or dynamic cluster setting; `log4j2.properties` only configures logging.$ecev2$, $ecev2$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/settings.html","label":"Elasticsearch Reference — Configuring Elasticsearch"}]$ecev2$::jsonb, $ecev2$PUBLISHED$ecev2$::"QStatus", $ecev2$manual:elastic-seed$ecev2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $ecev2$ECE-P1$ecev2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ecev2$Where is the JVM heap size for an Elasticsearch node configured?$ecev2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ecev2$Installation and Configuration$ecev2$, 3, $ecev2$SINGLE$ecev2$::"QType", $ecev2$Which setting provides the list of master-eligible node addresses that a starting node probes to discover the cluster?$ecev2$, $ecev2$[{"id":"a","text":"discovery.seed_hosts"},{"id":"b","text":"cluster.initial_master_nodes"},{"id":"c","text":"network.publish_host"},{"id":"d","text":"transport.profiles.default.port"}]$ecev2$::jsonb, $ecev2$["a"]$ecev2$::jsonb, $ecev2$`discovery.seed_hosts` lists addresses used for node discovery (the seed hosts providers). `cluster.initial_master_nodes` is a one-time bootstrap-only setting; `network.publish_host` and transport profiles relate to binding/transport, not discovery seeding.$ecev2$, $ecev2$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/modules-discovery.html","label":"Elasticsearch Reference — Discovery and cluster formation"}]$ecev2$::jsonb, $ecev2$PUBLISHED$ecev2$::"QStatus", $ecev2$manual:elastic-seed$ecev2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $ecev2$ECE-P1$ecev2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ecev2$Which setting provides the list of master-eligible node addresses that a starting node probes to discover the cluster?$ecev2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ecev2$Installation and Configuration$ecev2$, 3, $ecev2$SINGLE$ecev2$::"QType", $ecev2$Which `node.roles` value makes a node store warm-tier shards for ILM data-tier allocation?$ecev2$, $ecev2$[{"id":"a","text":"node.roles: [ data_warm ]"},{"id":"b","text":"node.roles: [ warm ]"},{"id":"c","text":"node.roles: [ data, tier_warm ]"},{"id":"d","text":"node.tier: warm"}]$ecev2$::jsonb, $ecev2$["a"]$ecev2$::jsonb, $ecev2$Data tiers use dedicated roles `data_hot`, `data_warm`, `data_cold`, `data_frozen` (and generic `data`/`data_content`). The exact role is `data_warm`; `warm`, `tier_warm`, and `node.tier` are not valid role keywords.$ecev2$, $ecev2$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/modules-node.html","label":"Elasticsearch Reference — Node roles"}]$ecev2$::jsonb, $ecev2$PUBLISHED$ecev2$::"QStatus", $ecev2$manual:elastic-seed$ecev2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $ecev2$ECE-P1$ecev2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ecev2$Which `node.roles` value makes a node store warm-tier shards for ILM data-tier allocation?$ecev2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ecev2$Installation and Configuration$ecev2$, 2, $ecev2$SINGLE$ecev2$::"QType", $ecev2$Which setting names the cluster so that nodes only join the intended cluster?$ecev2$, $ecev2$[{"id":"a","text":"cluster.name"},{"id":"b","text":"node.name"},{"id":"c","text":"cluster.uuid"},{"id":"d","text":"discovery.cluster"}]$ecev2$::jsonb, $ecev2$["a"]$ecev2$::jsonb, $ecev2$`cluster.name` defines the logical cluster a node belongs to — nodes with the same `cluster.name` form one cluster. `node.name` identifies an individual node; `cluster.uuid` is generated automatically and not user-set.$ecev2$, $ecev2$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/settings.html","label":"Elasticsearch Reference — Configuring Elasticsearch"}]$ecev2$::jsonb, $ecev2$PUBLISHED$ecev2$::"QStatus", $ecev2$manual:elastic-seed$ecev2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $ecev2$ECE-P1$ecev2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ecev2$Which setting names the cluster so that nodes only join the intended cluster?$ecev2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ecev2$Installation and Configuration$ecev2$, 3, $ecev2$SINGLE$ecev2$::"QType", $ecev2$How are secure/sensitive settings (such as the S3 repository access key) stored for an Elasticsearch node?$ecev2$, $ecev2$[{"id":"a","text":"As plaintext in elasticsearch.yml"},{"id":"b","text":"In the Elasticsearch keystore via the elasticsearch-keystore tool"},{"id":"c","text":"In jvm.options"},{"id":"d","text":"As environment variables only"}]$ecev2$::jsonb, $ecev2$["b"]$ecev2$::jsonb, $ecev2$Sensitive settings belong in the encrypted Elasticsearch keystore, managed with `bin/elasticsearch-keystore add ...`. Putting credentials plaintext in `elasticsearch.yml` is insecure; `jvm.options` is JVM tuning only.$ecev2$, $ecev2$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/configuring-stack-security.html","label":"Elasticsearch Reference — Configure security"}]$ecev2$::jsonb, $ecev2$PUBLISHED$ecev2$::"QStatus", $ecev2$manual:elastic-seed$ecev2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $ecev2$ECE-P1$ecev2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ecev2$How are secure/sensitive settings (such as the S3 repository access key) stored for an Elasticsearch node?$ecev2$);
