INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ecev2$Installation and Configuration$ecev2$, 3, $ecev2$SINGLE$ecev2$::"QType", $ecev2$Which command-line tool generates an enrollment token so Kibana can connect securely to an 8.x cluster?$ecev2$, $ecev2$[{"id":"a","text":"bin/elasticsearch-create-enrollment-token -s kibana"},{"id":"b","text":"bin/elasticsearch-setup-passwords kibana"},{"id":"c","text":"bin/elasticsearch-certutil kibana"},{"id":"d","text":"bin/kibana-enroll"}]$ecev2$::jsonb, $ecev2$["a"]$ecev2$::jsonb, $ecev2$`elasticsearch-create-enrollment-token -s kibana` mints a Kibana enrollment token containing the CA fingerprint and connection info. `elasticsearch-certutil` generates certs; `setup-passwords` was the pre-8.x reset tool.$ecev2$, $ecev2$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/configuring-stack-security.html","label":"Elasticsearch Reference — Configure security"}]$ecev2$::jsonb, $ecev2$PUBLISHED$ecev2$::"QStatus", $ecev2$manual:elastic-seed$ecev2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $ecev2$ECE-P1$ecev2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ecev2$Which command-line tool generates an enrollment token so Kibana can connect securely to an 8.x cluster?$ecev2$);
