INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ecev2$Installation and Configuration$ecev2$, 3, $ecev2$MULTI$ecev2$::"QType", $ecev2$Select ALL recommended production bootstrap/OS settings for an Elasticsearch node.$ecev2$, $ecev2$[{"id":"a","text":"Increase the max file descriptors (e.g. 65535) for the elasticsearch user."},{"id":"b","text":"Increase `vm.max_map_count` to at least 262144."},{"id":"c","text":"Disable swap or enable `bootstrap.memory_lock: true`."},{"id":"d","text":"Run Elasticsearch as the root user for maximum permissions."}]$ecev2$::jsonb, $ecev2$["a","b","c"]$ecev2$::jsonb, $ecev2$High file descriptor limits, `vm.max_map_count >= 262144`, and disabling swap (or memory-locking) are documented production prerequisites. Running as root is explicitly discouraged for security.$ecev2$, $ecev2$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/settings.html","label":"Elasticsearch Reference — Configuring Elasticsearch"}]$ecev2$::jsonb, $ecev2$PUBLISHED$ecev2$::"QStatus", $ecev2$manual:elastic-seed$ecev2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $ecev2$ECE-P1$ecev2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ecev2$Select ALL recommended production bootstrap/OS settings for an Elasticsearch node.$ecev2$);
