INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ecev2$Indexing Data$ecev2$, 4, $ecev2$SINGLE$ecev2$::"QType", $ecev2$In a `_bulk` request, one of 500 operations fails with a mapping conflict. What happens to the rest?$ecev2$, $ecev2$[{"id":"a","text":"The entire bulk request is rolled back."},{"id":"b","text":"Only the failing operation fails; the others succeed, and the response `errors` flag is true with per-item status."},{"id":"c","text":"All operations after the failing one are skipped."},{"id":"d","text":"The index is locked."}]$ecev2$::jsonb, $ecev2$["b"]$ecev2$::jsonb, $ecev2$Bulk operations are independent. A failure affects only that item; the response has `errors: true` and a per-item `status`/`error`. There is no transactional rollback.$ecev2$, $ecev2$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/docs-bulk.html","label":"Elasticsearch Reference — Bulk API"}]$ecev2$::jsonb, $ecev2$PUBLISHED$ecev2$::"QStatus", $ecev2$manual:elastic-seed$ecev2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $ecev2$ECE-P2$ecev2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ecev2$In a `_bulk` request, one of 500 operations fails with a mapping conflict. What happens to the rest?$ecev2$);
