INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ecev2$Mappings and Text Analysis$ecev2$, 3, $ecev2$SINGLE$ecev2$::"QType", $ecev2$You define a custom analyzer with a `lowercase` token filter and an `html_strip` char filter. Which order is correct in the analysis chain?$ecev2$, $ecev2$[{"id":"a","text":"html_strip (char filter) runs first on raw text, then the tokenizer, then lowercase (token filter)"},{"id":"b","text":"lowercase runs first, then html_strip"},{"id":"c","text":"Both run after the tokenizer"},{"id":"d","text":"Char filters and token filters cannot be combined"}]$ecev2$::jsonb, $ecev2$["a"]$ecev2$::jsonb, $ecev2$Character filters (e.g. `html_strip`) operate on the raw character stream BEFORE tokenization. Token filters (e.g. `lowercase`) operate on tokens AFTER the tokenizer. They are routinely combined in a custom analyzer.$ecev2$, $ecev2$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/analysis-custom-analyzer.html","label":"Elasticsearch Reference — Create a custom analyzer"},{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/analysis.html","label":"Elasticsearch Reference — Text analysis"}]$ecev2$::jsonb, $ecev2$PUBLISHED$ecev2$::"QStatus", $ecev2$manual:elastic-seed$ecev2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $ecev2$ECE-P2$ecev2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ecev2$You define a custom analyzer with a `lowercase` token filter and an `html_strip` char filter. Which order is correct in the analysis chain?$ecev2$);
