INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ecev2$Installation and Configuration$ecev2$, 3, $ecev2$SINGLE$ecev2$::"QType", $ecev2$Which is true about file-realm vs native-realm users in Elasticsearch security?$ecev2$, $ecev2$[{"id":"a","text":"File realm users are defined in files on each node (managed with elasticsearch-users); native realm users are stored in a system index via the API"},{"id":"b","text":"Both are stored only in elasticsearch.yml"},{"id":"c","text":"Native realm users require LDAP"},{"id":"d","text":"File realm users are stored in the keystore"}]$ecev2$::jsonb, $ecev2$["a"]$ecev2$::jsonb, $ecev2$The file realm keeps users in node-local files (managed by `bin/elasticsearch-users`); the native realm stores users in a hidden security index, managed via the user-management APIs/Kibana. Neither lives in `elasticsearch.yml` or the keystore.$ecev2$, $ecev2$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/configuring-stack-security.html","label":"Elasticsearch Reference — Configure security"}]$ecev2$::jsonb, $ecev2$PUBLISHED$ecev2$::"QStatus", $ecev2$manual:elastic-seed$ecev2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $ecev2$ECE-P3$ecev2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ecev2$Which is true about file-realm vs native-realm users in Elasticsearch security?$ecev2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ecev2$Installation and Configuration$ecev2$, 3, $ecev2$TRUE_FALSE$ecev2$::"QType", $ecev2$True or False: In Elasticsearch 8.x, basic authentication and TLS are part of the free Basic license.$ecev2$, $ecev2$[{"id":"a","text":"True"},{"id":"b","text":"False"}]$ecev2$::jsonb, $ecev2$["a"]$ecev2$::jsonb, $ecev2$True. Since 6.8/7.1 and continuing in 8.x, core security (TLS, native realm authentication, RBAC) is included in the free Basic license; advanced features (SSO, field-level security) need a paid tier.$ecev2$, $ecev2$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/configuring-stack-security.html","label":"Elasticsearch Reference — Configure security"}]$ecev2$::jsonb, $ecev2$PUBLISHED$ecev2$::"QStatus", $ecev2$manual:elastic-seed$ecev2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $ecev2$ECE-P3$ecev2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ecev2$True or False: In Elasticsearch 8.x, basic authentication and TLS are part of the free Basic license.$ecev2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ecev2$Installation and Configuration$ecev2$, 3, $ecev2$SINGLE$ecev2$::"QType", $ecev2$Which setting controls how long a node waits to find a master before logging warnings / failing health (cluster formation timeout-related)?$ecev2$, $ecev2$[{"id":"a","text":"cluster.election.* / discovery timeouts in the discovery module"},{"id":"b","text":"http.max_content_length"},{"id":"c","text":"index.refresh_interval"},{"id":"d","text":"thread_pool.write.size"}]$ecev2$::jsonb, $ecev2$["a"]$ecev2$::jsonb, $ecev2$Discovery/election timeout settings (in the discovery module) govern master discovery/election behavior. `http.max_content_length`, `refresh_interval`, and thread pool sizing are unrelated to cluster formation.$ecev2$, $ecev2$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/modules-discovery.html","label":"Elasticsearch Reference — Discovery and cluster formation"}]$ecev2$::jsonb, $ecev2$PUBLISHED$ecev2$::"QStatus", $ecev2$manual:elastic-seed$ecev2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $ecev2$ECE-P3$ecev2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ecev2$Which setting controls how long a node waits to find a master before logging warnings / failing health (cluster formation timeout-related)?$ecev2$);
