INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ecev2$Indexing Data$ecev2$, 3, $ecev2$SINGLE$ecev2$::"QType", $ecev2$Disabling refresh during a large bulk load (`index.refresh_interval: -1`) primarily:$ecev2$, $ecev2$[{"id":"a","text":"Improves indexing throughput by avoiding frequent segment creation (re-enable/refresh afterwards)"},{"id":"b","text":"Makes documents immediately searchable"},{"id":"c","text":"Permanently prevents searching the index"},{"id":"d","text":"Deletes existing documents"}]$ecev2$::jsonb, $ecev2$["a"]$ecev2$::jsonb, $ecev2$Setting `refresh_interval: -1` stops periodic refreshes, reducing segment churn and boosting bulk indexing speed. You re-enable it (or call `_refresh`) afterward so data becomes searchable. It does not delete data.$ecev2$, $ecev2$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/indices-create-index.html","label":"Elasticsearch Reference — Create index API"}]$ecev2$::jsonb, $ecev2$PUBLISHED$ecev2$::"QStatus", $ecev2$manual:elastic-seed$ecev2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $ecev2$ECE-P3$ecev2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ecev2$Disabling refresh during a large bulk load (`index.refresh_interval: -1`) primarily:$ecev2$);
