INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ecev2$Indexing Data$ecev2$, 3, $ecev2$SINGLE$ecev2$::"QType", $ecev2$Which `op_type`/endpoint guarantees a document is only created and never overwrites an existing id?$ecev2$, $ecev2$[{"id":"a","text":"PUT <index>/_create/<id>"},{"id":"b","text":"PUT <index>/_doc/<id>"},{"id":"c","text":"POST <index>/_update/<id>"},{"id":"d","text":"POST <index>/_doc"}]$ecev2$::jsonb, $ecev2$["a"]$ecev2$::jsonb, $ecev2$`PUT /<index>/_create/<id>` (equivalent to `op_type=create`) returns 409 if the id already exists, never overwriting. `_doc/<id>` overwrites; `_update` modifies; `POST /_doc` auto-generates a new id.$ecev2$, $ecev2$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/docs-index_.html","label":"Elasticsearch Reference — Index API"}]$ecev2$::jsonb, $ecev2$PUBLISHED$ecev2$::"QStatus", $ecev2$manual:elastic-seed$ecev2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $ecev2$ECE-P3$ecev2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ecev2$Which `op_type`/endpoint guarantees a document is only created and never overwrites an existing id?$ecev2$);
